Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (107,'노을공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27691&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','90년대까지 난지도란 이름의 쓰레기 매립장이었던 노을공원은 환경 재생사업을 통해 월드컵공원으로 탈바꿈하면서 이제는 사계절 내내 멋진 노을을 감상할 수 있는 명소가 되었다.','03900 서울 마포구 하늘공원로 84 (상암동, 한국지역난방공사)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (108,'봉산','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27690&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서울 은평구와 경기도 고양 사이에 있는 봉산은 서울 서쪽의 경계를 이룬 산이다.','03424 서울 은평구 서오릉로23길 8-5 (수국사)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (109,'아차산','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27689&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','한강과 도시가 어우러진 풍경을 즐길 수 있는 아차산','04948 서울 광진구 영화사로 135 (아차산등산로 입구)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (110,'서래섬','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=27688&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','서래섬은 동작대교와 반포대교 사이에 있는 작은 인공 섬이다.','06500 서울 서초구 신반포로11길 40 (반포동, 한강공원 반포 안내센터)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (1,'도봉산','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3599&fileTy=POSTTHUMB&fileNo=5&thumbTy=M','하늘을 깎아세운 만길 봉우리도봉(道峰)산은 이름 그대로 봉우리가 길인 산','132-010 서울특별시 도봉구 도봉동 경기 의정부시, 양주시 장흥면 일대',37);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (2,'청계천','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=34&fileTy=POSTTHUMB&fileNo=6&thumbTy=M','600년 서울의 역사가 하천의 물길 속으로 종로구와 중구 사이를 가르는 10.84km의 하천. 600년 수도 서울이 가지는 역사이기도 하고, 서울 시민 개개인이 가진 소소한 추억이기도 하다.','03187 서울 종로구 무교로 37 (서린동)',24);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (3,'남산공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3633&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','남산공원은 서울에 있는 공원 중에서 가장 넓은 시민공원이다. 크게 장충지구와 예장지구, 회현지구, 한남지구로 나눌 수 있다.','04628 서울특별시 중구 삼일대로 231',19);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (4,'한강','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=15060&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','한강은 서울에서 가장 중요한 지표로 도시를 남과 북으로 나눈다. 강변 양쪽으로 공원이나 다른 휴양시설이 다양해 자전거를 즐기거나, 크루즈를 타거나, 조류 관찰을 하기에도 알맞다.','07243 서울 영등포구 여의공원로 68',5);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (5,'북한산국립공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=369&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','1년 내내 새 코스를 발견하는 재미북한산국립공원은 산성 주능선, 우이능선, 비봉능선, 형제능선, 의상능선, 진달래능선 등 수많은 능선과 계곡이 펼쳐져 있어 1년 내내 오르내려도 늘 새롭다.','02700 서울 성북구 보국문로34길 6-21 (정릉동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (6,'여의도 공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2161&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','여의도 공원은 서울 영등포구 여의도동에 위치한 시민공원이다.','07243 서울 영등포구 여의공원로 68 (여의도동, 여의도공원관리사무소)',2);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (7,'올림픽공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2139&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서울올림픽을 기념하며 올림픽공원은 서울올림픽을 기념해 조성한 공원이다. 1984년에 2년 후의 아시안게임과 4년 후의 올림픽을 앞두고 공사를 시작했다.','05540 서울 송파구 올림픽로 424 (방이동, 올림픽공원)',2);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (23,'북서울꿈의숲','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4823&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','북서울꿈의숲은 복잡한 도심 속에서 시원하게 트인 풍경과 자연을 만날 수 있는 대형 녹지 공원이다.','01228 서울특별시 강북구 월계로 173 (번동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (24,'보라매공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2189&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','동작구 신대방동에 있는 보라매공원은 과거 공군사관학교로 사용되던 중 서울시에서 인수해 복지 및 편의시설이 마련된 시립공원으로 재탄생했다.','07062 서울 동작구 여의대방로20길 33 (신대방동, 보라매공원)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (25,'양재시민의 숲','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2158&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','양재시민의 숲은 서울 서초구 양재동에 위치한 공원','06773 서울특별시 서초구 매헌로 99 (양재동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (27,'여의도샛강생태공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=5032&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','여의도 샛강 생태공원은 생태계 보전을 위해 마련된 국내 최초의 생태공원이다.','07323 서울 영등포구 여의동로 48 (여의도샛강생태공원 방문자센터)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (28,'토성산성어울길','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=6606&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','토성산성어울길은 몽촌토성에서 남한산성까지 이어진다 하여 명칭을 얻었으며 크게 몽촌토성길과 남한산성 두 개의 코스로 나뉜다.','서울특별시 송파구 올림픽로 424 (방이동) 올림픽공원',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (29,'몽촌토성','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2210&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','올림픽공원 내 자리해 있는 몽촌토성은 백제 초기의 토성으로 전체 둘레는 약 2.7㎞에 달한다.','05540 서울특별시 송파구 올림픽로 424 (방이동)',1);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (30,'낙성대 공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3008&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','강감찬 장군을 기려 조성한 낙성대 공원은 서울특별시 관악구 봉천동에 위치해 있다.','08799 서울 관악구 낙성대로 77 (봉천동, 낙성대공원)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (31,'망원 한강공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2841&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','성산대교와 양화대교 사이 한강 북단에 만들어진 망원지구는 아름다운 전망과 역사유적이 많은 곳이다.','04005 서울특별시 마포구 마포나루길 467 (망원동) 한강공원망원지구사무소',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (32,'월드컵공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2119&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','1978~93년 15년간 쌓인 쓰레기 매립지는 거대한 산을 이뤘다. 하지만 서울시의 ''골칫덩어리'' 매립지 위에 생태공원이 조성되면서 지금은 서울시민의 가장 사랑받는 월드컵 공원으로 거듭났다','03900 서울특별시 마포구 하늘공원로 108-1',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (33,'청운공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3136&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','서울특별시 종로구 청운동에 위치한 청운공원은 자하문 옆 윤동주 시인의 언덕부터 청운 어린이집 부근까지 포괄해서 일컫는다.','서울시 종로구 창의문로 119 (청운동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (34,'불암산','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=3828&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','노원구와 남양주시에 걸쳐있는 불암산은 산 정상에 있는 큰 바위가 송낙을 쓴 부처님의 모습을 닮았다고 하여 불암산이라는 명칭을 갖게 되었다.','01716 서울특별시 노원구 덕릉로94길 73 (중계동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (35,'길동생태공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4064&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','길동자연생태공원은 시민들에게 동·식물, 곤충들이 자연 속에서 활동하는 모습을 관찰할 수 있도록 하기 위해 조성되었다.','05291 서울 강동구 천호대로 1291 (길동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (36,'북악산 야경','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=16324&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','북악산은 보안상의 이유로 서울의 많은 산 중에서 가장 늦게 개방되었다.','03010 서울 종로구 북악산로 267 (평창동, 북악팔각정)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (37,'서서울호수공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=4928&fileTy=POSTTHUMB&fileNo=3&thumbTy=M','신월정수장이 문을 닫으며 재탄생된 생태공원','07916 서울 양천구 남부순환로64길 20 (신월동, 공원관리사무소)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (38,'도산공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=1789&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','도산공원은 서울 강남구 신사동에 있는 공원으로 도산 안창호의 애국정신과 교육 정신을 기리고자 조성되었다.','06020 서울 강남구 도산대로45길 20 (도산전시관)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (39,'마포대교 바람의 길 & 서울색공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11237&fileTy=POSTTHUMB&fileNo=1&thumbTy=M','여의도 랜드마크 중 하나인 바람의 길은 한강과 서울의 경치를 감상할 수 있는 전망대 기능의 대형조형물이다.','07337 서울 영등포구 여의동로 330 (여의도동, 한강사업본부 여의도안내센터)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (40,'마로니에공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=2087&fileTy=POSTTHUMB&fileNo=4&thumbTy=M','마로니에공원은 젊음과 문화의 상징인 대학로라는 공간의 특성과 상통하는 문화적 향취를 가진 곳이다.','03086 서울 종로구 대학로8길 1 (동숭동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (41,'현대원서공원','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=12315&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','현대원서공원은 현대건설이 그룹 사옥건립 때 기업 이익의 사회 환원과 시민 휴식을 위한 녹지 공간 조성을 목적으로 만든 곳이다.','03058 서울특별시 종로구 창덕궁길 19 (원서동)',0);
Insert into HR.SEOUL_NATURE (NO,TITLE,POSTER,MSG,ADDRESS,HIT) values (42,'뚝섬유원지','https://korean.visitseoul.net/comm/getImage?srvcId=POST&parentSn=11399&fileTy=POSTTHUMB&fileNo=2&thumbTy=M','뚝섬유원지는 뚝섬의 한강 변 일대에 조성된 시민공원이다. 야외수영장, 놀이터, 스케이트보드장, 클라이밍장 등 각종 편의시설이 구비되어 있어 여름에는 수상스포츠를, 겨울에는 눈썰매와 스케이트를 즐길 수 있다.','05097 서울특별시 광진구 강변북로 139 (자양동)',0);
